{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "forge/project.schema.json",
  "title": "Forge Project Schema",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "name",
    "description",
    "type",
    "metadata_path",
    "code_path",
    "github_url",
    "github_board"
  ],
  "properties": {
    "name": {
      "type": "string",
      "minLength": 1
    },
    "description": {
      "type": "string",
      "minLength": 1
    },
    "type": {
      "type": "string",
      "enum": [
        "opensource",
        "closedsource"
      ]
    },
    "metadata_path": {
      "type": "string",
      "minLength": 1
    },
    "code_path": {
      "type": "string",
      "minLength": 1
    },
    "github_url": {
      "type": "string",
      "minLength": 1,
      "description": "Repository URL (e.g. https://github.com/org/repo) used to resolve owner/repo for GitHub APIs."
    },
    "github_board": {
      "type": "string",
      "minLength": 1,
      "description": "GitHub Projects (v2) board URL, e.g. https://github.com/orgs/org-name/projects/3 — not the issues list URL."
    },
    "doc_repo": {
      "type": "string",
      "description": "Optional: name of a folder in the Cursor multi-root workspace that contains the documentation repository (sibling of the application repo). Used by /build-from-github for auto-documentation."
    }
  }
}

